#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long P,a,b,c,x,y;
        scanf("%lld %lld %lld %lld %lld %lld", &P,&a,&b,&c,&x,&y);
        long long w1 = a*x + b;
        long long w2 = a*y + c;
        long long mn = w1 < w2 ? w1 : w2;
        long long ans = P / mn;
        printf("%lld\n", ans);
    }
    return 0;
}

